CREATE TYPE "JsaStatus" AS ENUM ('DRAFT','UNDER_REVIEW','APPROVED','ACTIVE','SUPERSEDED','ARCHIVED');CREATE TYPE "JsaControlHierarchy" AS ENUM ('ELIMINATION','SUBSTITUTION','ENGINEERING','ADMINISTRATIVE','PPE');
CREATE TABLE "JobSafetyAnalysis" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"siteId" TEXT NOT NULL,"departmentId" TEXT,"reference" TEXT NOT NULL,"title" TEXT NOT NULL,"jobDescription" TEXT NOT NULL,"workLocation" TEXT,"requiredCompetency" TEXT,"requiredPpe" TEXT,"emergencyRequirements" TEXT,"version" INTEGER NOT NULL DEFAULT 1,"status" "JsaStatus" NOT NULL DEFAULT 'DRAFT',"ownerId" TEXT,"createdById" TEXT NOT NULL,"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"effectiveDate" TIMESTAMP(3),"reviewDueDate" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "JobSafetyAnalysis_pkey" PRIMARY KEY("id"));
CREATE TABLE "JsaStep" ("id" TEXT NOT NULL,"jsaId" TEXT NOT NULL,"sequence" INTEGER NOT NULL,"taskStep" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "JsaStep_pkey" PRIMARY KEY("id"));
CREATE TABLE "JsaHazard" ("id" TEXT NOT NULL,"stepId" TEXT NOT NULL,"hazard" TEXT NOT NULL,"potentialConsequence" TEXT NOT NULL,"initialLikelihood" "RiskLikelihood" NOT NULL,"initialImpact" "RiskImpact" NOT NULL,"initialScore" INTEGER NOT NULL,"residualLikelihood" "RiskLikelihood" NOT NULL,"residualImpact" "RiskImpact" NOT NULL,"residualScore" INTEGER NOT NULL,"riskId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "JsaHazard_pkey" PRIMARY KEY("id"));
CREATE TABLE "JsaControl" ("id" TEXT NOT NULL,"hazardId" TEXT NOT NULL,"hierarchy" "JsaControlHierarchy" NOT NULL,"description" TEXT NOT NULL,"responsibleRole" TEXT,"verificationRequired" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "JsaControl_pkey" PRIMARY KEY("id"));
CREATE TABLE "JsaAcknowledgment" ("id" TEXT NOT NULL,"jsaId" TEXT NOT NULL,"userId" TEXT NOT NULL,"acknowledgedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"statement" TEXT,CONSTRAINT "JsaAcknowledgment_pkey" PRIMARY KEY("id"));
CREATE UNIQUE INDEX "JobSafetyAnalysis_organizationId_reference_version_key" ON "JobSafetyAnalysis"("organizationId","reference","version");CREATE INDEX "JobSafetyAnalysis_organizationId_status_idx" ON "JobSafetyAnalysis"("organizationId","status");CREATE INDEX "JobSafetyAnalysis_siteId_status_idx" ON "JobSafetyAnalysis"("siteId","status");CREATE INDEX "JobSafetyAnalysis_ownerId_reviewDueDate_idx" ON "JobSafetyAnalysis"("ownerId","reviewDueDate");CREATE UNIQUE INDEX "JsaStep_jsaId_sequence_key" ON "JsaStep"("jsaId","sequence");CREATE INDEX "JsaHazard_stepId_idx" ON "JsaHazard"("stepId");CREATE INDEX "JsaHazard_riskId_idx" ON "JsaHazard"("riskId");CREATE INDEX "JsaControl_hazardId_hierarchy_idx" ON "JsaControl"("hazardId","hierarchy");CREATE UNIQUE INDEX "JsaAcknowledgment_jsaId_userId_key" ON "JsaAcknowledgment"("jsaId","userId");CREATE INDEX "JsaAcknowledgment_userId_acknowledgedAt_idx" ON "JsaAcknowledgment"("userId","acknowledgedAt");
ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_organizationId_fkey" FOREIGN KEY("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_siteId_fkey" FOREIGN KEY("siteId") REFERENCES "Site"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_departmentId_fkey" FOREIGN KEY("departmentId") REFERENCES "Department"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_ownerId_fkey" FOREIGN KEY("ownerId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_createdById_fkey" FOREIGN KEY("createdById") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "JobSafetyAnalysis" ADD CONSTRAINT "JobSafetyAnalysis_approvedById_fkey" FOREIGN KEY("approvedById") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "JsaStep" ADD CONSTRAINT "JsaStep_jsaId_fkey" FOREIGN KEY("jsaId") REFERENCES "JobSafetyAnalysis"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JsaHazard" ADD CONSTRAINT "JsaHazard_stepId_fkey" FOREIGN KEY("stepId") REFERENCES "JsaStep"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JsaHazard" ADD CONSTRAINT "JsaHazard_riskId_fkey" FOREIGN KEY("riskId") REFERENCES "Risk"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "JsaControl" ADD CONSTRAINT "JsaControl_hazardId_fkey" FOREIGN KEY("hazardId") REFERENCES "JsaHazard"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JsaAcknowledgment" ADD CONSTRAINT "JsaAcknowledgment_jsaId_fkey" FOREIGN KEY("jsaId") REFERENCES "JobSafetyAnalysis"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "JsaAcknowledgment" ADD CONSTRAINT "JsaAcknowledgment_userId_fkey" FOREIGN KEY("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
